/* ============================================================
   HYDRATE DATA  (no sentinel comparison; just parse the island)
============================================================ */
window.MATRIX_DATA = [];
try {
  var el = document.getElementById('matrixDataJson');
  if (el) {
    var txt = el.textContent.trim();
    if (txt && txt.charAt(0) === '[') {
      var parsed = JSON.parse(txt);
      if (Array.isArray(parsed)) window.MATRIX_DATA = parsed;
    }
  }
} catch(e) {
  console.warn('[NIRF comparison] Data parse failed:', e);
}

/* ============================================================
   RENDER MATRIX
============================================================ */
function rankBubbleClass(r) {
  if (r == null) return 'unranked';
  if (r <= 5) return 'r1-5';
  if (r <= 10) return 'r6-10';
  if (r <= 25) return 'r11-25';
  return 'r26-50';
}
function rankCell(r) {
  if (r == null) return '<span class="rank-bubble unranked">&mdash;</span>';
  return '<span class="rank-bubble ' + rankBubbleClass(r) + '">' + r + '</span>';
}
function moveCell(r2023, r2025) {
  if (r2023 == null && r2025 != null) return '<span class="move-badge new">NEW IN TOP 30</span>';
  if (r2023 != null && r2025 == null) return '<span class="move-badge down">DROPPED OUT</span>';
  if (r2023 == null || r2025 == null) return '<span class="move-badge same">&mdash;</span>';
  var delta = r2023 - r2025; // positive = climbed
  if (delta > 0) return '<span class="move-badge up">&uarr; +' + delta + '</span>';
  if (delta < 0) return '<span class="move-badge down">&darr; ' + delta + '</span>';
  return '<span class="move-badge same">&mdash; same</span>';
}

var currentFilter = 'all';
function renderMatrix() {
  var tbody = document.getElementById('matrixBody');
  if (!tbody) return;
  var rows = window.MATRIX_DATA.slice();
  if (currentFilter === 'iit') rows = rows.filter(function(r){ return r.type === 'IIT'; });
  else if (currentFilter === 'nit') rows = rows.filter(function(r){ return r.type === 'NIT'; });
  else if (currentFilter === 'private') rows = rows.filter(function(r){ return r.type === 'Private'; });
  else if (currentFilter === 'climbers') {
    rows = rows.filter(function(r){
      if (r.rank2023 == null || r.rank2025 == null) return false;
      return (r.rank2023 - r.rank2025) >= 4;
    }).sort(function(a, b){ return (b.rank2023 - b.rank2025) - (a.rank2023 - a.rank2025); });
  }
  else if (currentFilter === 'fallers') {
    rows = rows.filter(function(r){
      if (r.rank2023 == null || r.rank2025 == null) return false;
      return (r.rank2023 - r.rank2025) <= -4;
    }).sort(function(a, b){ return (a.rank2023 - a.rank2025) - (b.rank2023 - b.rank2025); });
  } else {
    // All: sort by 2025 rank, unranked last
    rows.sort(function(a, b){
      var ra = a.rank2025 == null ? 9999 : a.rank2025;
      var rb = b.rank2025 == null ? 9999 : b.rank2025;
      return ra - rb;
    });
  }

  if (!rows.length) {
    tbody.innerHTML = '<tr><td colspan="6" style="padding:60px;text-align:center;color:var(--muted)">No institutions match this filter.</td></tr>';
    return;
  }

  tbody.innerHTML = rows.map(function(r) {
    return '<tr>' +
             '<td>' +
               '<div class="col-name">' + r.name + '</div>' +
               '<div class="col-meta">' + (r.location || '') + '</div>' +
             '</td>' +
             '<td class="rank-cell">' + rankCell(r.rank2023) + '</td>' +
             '<td class="rank-cell">' + rankCell(r.rank2024) + '</td>' +
             '<td class="rank-cell">' + rankCell(r.rank2025) + '</td>' +
             '<td class="move-cell">' + moveCell(r.rank2023, r.rank2025) + '</td>' +
             '<td><span style="font-family:\'JetBrains Mono\',monospace;font-size:11px;color:var(--muted);letter-spacing:.06em;text-transform:uppercase">' + r.type + '</span></td>' +
           '</tr>';
  }).join('');
}

function setupFilters() {
  var pills = document.querySelectorAll('.filter-pill');
  Array.prototype.forEach.call(pills, function(p) {
    p.addEventListener('click', function() {
      Array.prototype.forEach.call(pills, function(x){ x.classList.remove('active'); });
      p.classList.add('active');
      currentFilter = p.getAttribute('data-filter');
      renderMatrix();
    });
  });
}

/* ============================================================
   CHARTS
============================================================ */
function renderTrajectoryChart() {
  var el = document.getElementById('trajectoryChart');
  if (!el || typeof Chart === 'undefined') return;
  // Top 10 by 2025 rank, with valid 3-year data
  var top10 = window.MATRIX_DATA.filter(function(r){
    return r.rank2025 != null && r.rank2025 <= 10 && r.rank2023 != null;
  }).sort(function(a, b){ return a.rank2025 - b.rank2025; });

  var palette = ['#0E3A8A','#FF6B0A','#0A2560','#FF8A3D','#1F8B5C','#E89A1C','#5A6278','#C23A3A','#071A44','#9B6B3F'];
  var datasets = top10.map(function(r, i) {
    return {
      label: r.shortName || r.name,
      data: [r.rank2023, r.rank2024, r.rank2025],
      borderColor: palette[i % palette.length],
      backgroundColor: palette[i % palette.length],
      borderWidth: 2.5,
      tension: 0.25,
      pointRadius: 5,
      pointHoverRadius: 7,
      pointBorderWidth: 2,
      pointBackgroundColor: '#FFFDF7'
    };
  });

  new Chart(el, {
    type: 'line',
    data: { labels: ['2023', '2024', '2025'], datasets: datasets },
    options: {
      responsive: true, maintainAspectRatio: false,
      interaction: { mode: 'index', intersect: false },
      plugins: {
        legend: { position: 'bottom', labels: { font: { family: "'Plus Jakarta Sans'", size: 11, weight: '500' }, color: '#0E1B3D', padding: 12, usePointStyle: true, pointStyle: 'circle', boxWidth: 8 } },
        tooltip: {
          backgroundColor: '#071A44', padding: 12, cornerRadius: 8,
          titleFont: { family: "'Plus Jakarta Sans'", size: 13, weight: '600' },
          bodyFont: { family: "'Plus Jakarta Sans'", size: 12 },
          callbacks: { label: function(item) { return item.dataset.label + ': rank ' + item.parsed.y; } }
        }
      },
      scales: {
        x: { grid: { color: '#E8DFC8' }, ticks: { color: '#5A6278', font: { family: "'JetBrains Mono'", size: 11 } } },
        y: {
          reverse: true, min: 0, max: 22,
          title: { display: true, text: 'NIRF Rank (lower = better)', color: '#5A6278', font: { family: "'JetBrains Mono'", size: 10 } },
          grid: { color: '#E8DFC8' },
          ticks: { stepSize: 2, color: '#5A6278', font: { family: "'JetBrains Mono'", size: 10 } }
        }
      }
    }
  });
}

function renderScoreChart() {
  var el = document.getElementById('scoreChart');
  if (!el || typeof Chart === 'undefined') return;
  // Top 6 by 2025 with scores available for all 3 years
  var top6 = window.MATRIX_DATA.filter(function(r){
    return r.score2023 != null && r.score2024 != null && r.score2025 != null;
  }).sort(function(a, b){ return a.rank2025 - b.rank2025; }).slice(0, 6);

  var palette = ['#0E3A8A','#FF6B0A','#0A2560','#FF8A3D','#1F8B5C','#E89A1C'];
  var datasets = ['2023', '2024', '2025'].map(function(yr, i) {
    var shade = ['#0E3A8A','#FF6B0A','#0A2560'][i];
    return {
      label: 'Score ' + yr,
      data: top6.map(function(r){ return r['score' + yr]; }),
      backgroundColor: shade,
      borderRadius: 4,
      borderSkipped: false
    };
  });

  new Chart(el, {
    type: 'bar',
    data: { labels: top6.map(function(r){ return r.shortName || r.name; }), datasets: datasets },
    options: {
      responsive: true, maintainAspectRatio: false,
      plugins: {
        legend: { position: 'bottom', labels: { font: { family: "'Plus Jakarta Sans'", size: 11, weight: '500' }, color: '#0E1B3D', padding: 12, usePointStyle: true, pointStyle: 'rect', boxWidth: 10 } },
        tooltip: {
          backgroundColor: '#071A44', padding: 12, cornerRadius: 8,
          titleFont: { family: "'Plus Jakarta Sans'", size: 13, weight: '600' },
          bodyFont: { family: "'Plus Jakarta Sans'", size: 12 },
          callbacks: { label: function(item) { return item.dataset.label + ': ' + item.parsed.y.toFixed(2); } }
        }
      },
      scales: {
        x: { grid: { display: false }, ticks: { color: '#0E1B3D', font: { family: "'Plus Jakarta Sans'", size: 10, weight: '500' } } },
        y: { beginAtZero: false, min: 65, max: 95, grid: { color: '#E8DFC8' }, ticks: { color: '#5A6278', font: { family: "'JetBrains Mono'", size: 10 } } }
      }
    }
  });
}

/* ============================================================
   REVEAL ON SCROLL
============================================================ */
function setupReveal() {
  if (!('IntersectionObserver' in window)) {
    Array.prototype.forEach.call(document.querySelectorAll('.reveal'), function(el){ el.classList.add('visible'); });
    return;
  }
  var io = new IntersectionObserver(function(entries){
    entries.forEach(function(e){
      if (e.isIntersecting) { e.target.classList.add('visible'); io.unobserve(e.target); }
    });
  }, { threshold: 0.12, rootMargin: '0px 0px -40px 0px' });
  Array.prototype.forEach.call(document.querySelectorAll('.reveal'), function(el){ io.observe(el); });
}

/* ============================================================
   INIT
============================================================ */
function safe(name, fn) {
  try { fn(); } catch(e) { console.error('[NIRF comparison] ' + name + ' failed:', e); }
}
function init() {
  document.documentElement.classList.add('js-ready');

  safe('renderMatrix', renderMatrix);
  safe('setupFilters', setupFilters);

  if (typeof Chart !== 'undefined') {
    safe('renderTrajectoryChart', renderTrajectoryChart);
    safe('renderScoreChart', renderScoreChart);
  } else {
    Array.prototype.forEach.call(document.querySelectorAll('.chart-wrap'), function(el) {
      el.innerHTML = '<div style="height:100%;display:flex;align-items:center;justify-content:center;color:var(--muted);font-size:13px;text-align:center;padding:20px;font-family:\'JetBrains Mono\',monospace;letter-spacing:.06em">Chart unavailable offline.<br>Connect to render.</div>';
    });
  }

  safe('nav-wire', function() {
    Array.prototype.forEach.call(document.querySelectorAll('.nav-links a'), function(a) {
      a.addEventListener('click', function(){
        var n = document.getElementById('navLinks');
        if (n) n.classList.remove('open');
      });
    });
  });
  safe('setupReveal', setupReveal);
}

if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', init);
} else {
  init();
}

